  ('locality-1fb53453-moex-00050', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '關於訴願期間行政處分停止執行之敘述，下列何者錯誤？ 訴願人於訴願程序終結前，亦得向行政法院聲請停止執行 原行政處分之執行，原則上不因提起訴願而停止 訴願人僅得就原行政處分之全部聲請停止執行，以維護行政權之完整性 受理訴願機關認為原行政處分之合法性顯有疑義，得依職權命原處分機關停止執行', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
  ('locality-1fb53453-moex-00051', 'locality-1fb53453', 'locality-1fb53453-moex-114-3082b5f1', 'sub-locality-1fb53453-02', NULL, 'single_choice', '甲為公益團體，認為A工廠長年違法傾倒廢棄物，致使周遭農地受到污染，遂依廢棄物清理法規 定，以書面向當地主管機關乙請求依法行使公權力。若乙未在法定期間內採取任何作為，而甲欲 依行政訴訟法規定提起公益訴訟時，下列敘述何者正確？ 本案仍應視其具體主張而提起特定訴訟類型 甲必須證明自身權益亦遭受損害，始得提起本案訴訟 向行政法院提起訴訟前，一律須經訴願程序 此種訴訟屬於備位性質，必須限於無法提起其他行政訴訟時，始得提起', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:33+00:00", "source_pdf_sha1": "91bb7df14e6a", "answer_pdf_sha1": "131e6ee68ca1", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "501", "s": "0608", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "locality", "civil_category": "財經廉政"}'::jsonb, NULL),
